// CUDA Kernel: Fan1
// Corresponds to OpenCL kernel Fan1
__global__ void Fan1_cuda(float *m_dev,
                          float *a_dev,
                          float *b_dev,
                          const int size,
                          const int t) {
    int globalId = blockIdx.x * blockDim.x + threadIdx.x;

    if (globalId < size - 1 - t) {
        // Index calculation: size * (globalId + t + 1) + t
        int row = globalId + t + 1;
        int col = t;
        int idx = size * row + col;
        int pivot_idx = size * t + t;

        m_dev[idx] = a_dev[idx] / a_dev[pivot_idx];
    }
}

// CUDA Kernel: Fan2
// Corresponds to OpenCL kernel Fan2
__global__ void Fan2_cuda(float *m_dev,
                          float *a_dev,
                          float *b_dev,
                          const int size,
                          const int t) {
    int globalIdx = blockIdx.x * blockDim.x + threadIdx.x;
    int globalIdy = blockIdx.y * blockDim.y + threadIdx.y;

    if (globalIdx < size - 1 - t && globalIdy < size - t) {
        int row = globalIdx + 1 + t;
        int col = globalIdy + t;

        // a_dev[size*(globalIdx+1+t)+(globalIdy+t)] -= m_dev[size*(globalIdx+1+t)+t] * a_dev[size*t+(globalIdy+t)];
        int a_idx = size * row + col;
        int m_idx = size * row + t;
        int pivot_row_idx = size * t + col;

        a_dev[a_idx] -= m_dev[m_idx] * a_dev[pivot_row_idx];

        if (globalIdy == 0) {
            // b_dev[globalIdx+1+t] -= m_dev[size*(globalIdx+1+t)+(globalIdy+t)] * b_dev[t];
            // Note: In the source, globalIdy is 0 here, so the index for m_dev is size*(globalIdx+1+t)+0
            // However, looking at the source logic: m_dev[size*(globalIdx+1+t)+(globalIdy+t)] where globalIdy=0 -> m_dev[size*(row)+t]
            // Wait, source says: m_dev[size*(globalIdx+1+t)+(globalIdy+t)]
            // If globalIdy=0, index is size*(globalIdx+1+t) + t.
            // This matches the m_idx calculated above.

            int b_idx = globalIdx + 1 + t;
            b_dev[b_idx] -= m_dev[m_idx] * b_dev[t];
        }
    }
}

